VALUES
  ('judicial-cf446b4c-moex-00084', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-114-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲有子女乙、丙、丁。甲於遺囑中委託好友戊指定甲之遺囑執行人。甲死亡後，下列敘述何者正確？', '["戊若已死亡，丁得逕向法院聲請指定遺囑執行人", "戊得指定自己16歲之兒子庚為遺囑執行人", "戊得指定丙26歲之兒子癸為遺囑執行人", "戊得指定自己76歲但受輔助宣告之媽媽辛為遺囑執行人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "ddd795ca1711", "answer_pdf_sha1": "0205d3c8521a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "203", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
