  ('judicial-cf446b4c-moex-00086', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關刑法地之效力，下列敘述何者正確？', '["犯罪之結果在我國領域內者，適用我國刑法", "犯罪行為與結果皆在我國領域內者，始適用我國刑法", "外國人於我國領域內犯罪，不適用我國刑法", "外國人於我國領域外對於我國人民犯罪，一律不適用我國刑法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
