  ('judicial-cf446b4c-moex-00088', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何種事實係屬行為人故意必須認知的對象？', '["客觀構成要件", "客觀處罰條件", "量刑條件", "追訴條件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00089', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何者非屬阻卻違法事由？', '["瘖啞人之行為", "依法令之行為", "業務上之正當行為", "正當防衛之行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00090', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關被害人承諾之敘述，下列何者正確？', '["被害人承諾為法定阻卻違法事由", "被害人承諾所放棄之法益，不包含生命法益、各種程度的身體健康法益", "國家法益、社會法益不在被害人承諾所得處分的範圍之內", "被害人需滿20歲，其所為之承諾方屬有效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00091', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲的女友A另結新歡而向甲提議分手。甲憤恨不已，決定與A同歸於盡，因而開車前往A的住處。途中 甲一路盤算著要如何進行，開車不慎撞到某行人，當場撞死。甲趕緊下車察看，赫然發現竟是A。甲應如 何論罪？', '["故意殺人罪", "遺棄罪", "不能安全駕駛罪", "過失致死罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00092', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲患有思覺失調症，某日發病時毆打乙成傷，經精神科醫師鑑定後，甲行為當時已完全喪失辨識其行為違 法之判斷能力。有關甲之敘述，下列何者正確？', '["甲為無責任能力人", "甲為限制責任能力人", "甲為瘖啞人", "甲為完全責任能力人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00093', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列犯罪，何者有處罰過失犯？', '["公務員洩漏國防以外之秘密罪（刑法第132條）", "強制性交罪（刑法第221條）", "毀損罪（刑法第354條）", "肇事逃逸罪（刑法第185條之4）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
